import{_ as e,c as p,o as i,a8 as l}from"./chunks/framework.DMZhn_gK.js";const t="/assets/image-20260412173046276.DdnfWK53.png",s="/assets/image-20260412171444655.B3emalH2.png",r="/assets/image-20260412174832167.Cel6oRkU.png",o="/assets/image-20260412175857599.BRwGyyGG.png",n="/assets/image-20260412213151331.DMfS0TWP.png",d="/assets/image-20260412213728040.DKQUs3Qm.png",c="/assets/image-20260412214209760.B2Bqmvst.png",f=JSON.parse('{"title":"Milvus 向量数据库","description":"RAG文本检索增强","frontmatter":{"title":"Milvus 向量数据库","tags":["transform","向量数据库，Milvus"],"categories":["Milvus"],"date":"2026-3-23","description":"RAG文本检索增强","articleGPT":"RAG文本检索增强","references":[{"title":"Java","url":"https://github.com/imsyy/vitepress-theme-curve"}]},"headers":[],"relativePath":"ModelTraning/Milvus.md","filePath":"ModelTraning/Milvus.md","lastUpdated":1776154279000}'),m={name:"ModelTraning/Milvus.md"};function h(u,a,g,q,_,y){return i(),p("div",null,[...a[0]||(a[0]=[l('<h2 id="milvus向量数据库" tabindex="-1">Milvus向量数据库 <a class="header-anchor" href="#milvus向量数据库" aria-label="Permalink to &quot;Milvus向量数据库&quot;">​</a></h2><p>结构化数据与非结构化数据</p><p>非结构化数据</p><p>嵌入向量</p><p>做相似度检索， 离不开距离</p><h3 id="collection-和-field" tabindex="-1">Collection 和 Field <a class="header-anchor" href="#collection-和-field" aria-label="Permalink to &quot;Collection 和 Field&quot;">​</a></h3><p>IVF_FLAT：是基于倒排索引方法</p><ol><li>聚类</li><li>倒排索引</li></ol><p>IVF_SQ8： 在IVF基础商增加量化</p><p>HNSW 图索引</p><p>attu</p><p>Milvus数据的增删查改</p><p>分区检索</p><p>过滤检索</p><p>范围检索</p><p>向量检索</p><p>稠密检索</p><p>稀疏检索</p><p>RRFRanker排序器</p><p>加权排序器</p><p>总结： 加权排序器：注意不同检索器的度量不同，值域不一致，加权计算的时候可能有问题。需要归一化处理。</p><p>需要先删表再删库</p><h2 id="mysql-问答系统" tabindex="-1">MySQL 问答系统 <a class="header-anchor" href="#mysql-问答系统" aria-label="Permalink to &quot;MySQL 问答系统&quot;">​</a></h2><p>高频问答数据的缓存</p><h2 id="python日志记录简介与应用" tabindex="-1">Python日志记录简介与应用 <a class="header-anchor" href="#python日志记录简介与应用" aria-label="Permalink to &quot;Python日志记录简介与应用&quot;">​</a></h2><h2 id="bm25算法概述" tabindex="-1">BM25算法概述 <a class="header-anchor" href="#bm25算法概述" aria-label="Permalink to &quot;BM25算法概述&quot;">​</a></h2><p>BM25（BestMatching25）是一种信息检索领域的排名算法，用于计算查询（Query）与文档（Document）之间的相关性得分。它改进了传统的TF-IDF算法，引I入文档长度归一化和词频饱和机制，使检索结果更准确。</p><p>BM25原理</p><p>衡量一个词的稀有程度</p><p>引入长度归一化和词频</p><h2 id="redis在rag中的应用" tabindex="-1">Redis在RAG中的应用 <a class="header-anchor" href="#redis在rag中的应用" aria-label="Permalink to &quot;Redis在RAG中的应用&quot;">​</a></h2><h2 id="基于mysql的fqa问答系统实现" tabindex="-1">基于MySQL的FQA问答系统实现 <a class="header-anchor" href="#基于mysql的fqa问答系统实现" aria-label="Permalink to &quot;基于MySQL的FQA问答系统实现&quot;">​</a></h2><p><img src="'+t+'" alt="image-20260412173046276" loading="lazy"></p><p>jieba分词：文本预处理</p><p>0.85 走Mysql 或 Redis 否则走RAG</p><p>BM25分词管理</p><ol><li>先从redis获取数据</li><li>redis没有，从mysql中获取</li><li>获取问题进行分词，存入redis中</li></ol><p>RAG检索增强生成</p><p>Bert 二分类</p><p>混合检索 = 双路召回</p><h2 id="文档处理" tabindex="-1">文档处理 <a class="header-anchor" href="#文档处理" aria-label="Permalink to &quot;文档处理&quot;">​</a></h2><p>作用： 离线文档的读取与切块</p><p>离线文档存在形式 是以目录方式存在的</p><p>基本步骤： 0.预定义多种文档加载器 1.遍历目录，根据文档的扩展名称，选择文档加载器 2.定义文档分割器 包含父子分块的文档分割器 3.遍历每个文档，针对文档进行父子分块 4.返回所有的分块内容</p><p>mysqlqa redisqa ragqa</p><p>交叉编码BGE-m3 模型 BGE-reranker-large 模型</p><p><img src="'+s+'" alt="image-20260412171444655" loading="lazy"></p><p>稠密向量主要是语义编码</p><p>稀疏向量主要是关键词编码</p><p>知识库的增删改查</p><p>需要溯源字段， 需要file_path 文档路径</p><p>知识更新，找到知识库删除重新更新</p><p>还可以更多溯源字段： 文档页码</p><p><img src="'+r+'" alt="image-20260412174832167" loading="lazy"></p><p>侧重稠密向量 使用加权排序器排序， 粗排结果， 解析父文档，父子分块， 可能会出现多个子块对应一个父块，所以需要去重。筛选topK 混合检索与重排序</p><p>混合检索逻辑</p><p><img src="'+o+'" alt="image-20260412175857599" loading="lazy"></p><p>优化点：</p><h2 id="query改写" tabindex="-1">query改写 <a class="header-anchor" href="#query改写" aria-label="Permalink to &quot;query改写&quot;">​</a></h2><ol><li>结合历史会话改写</li><li>关键词扩写</li><li>假设问题检索</li><li>缩写词改写</li><li>一般去噪改写（回溯问题检索）</li><li>子查询改写（子查询检索）</li></ol><p>提高query质量适合问题检索</p><p>直接检索</p><h2 id="ragas-评估框架" tabindex="-1">RAGAS 评估框架 <a class="header-anchor" href="#ragas-评估框架" aria-label="Permalink to &quot;RAGAS 评估框架&quot;">​</a></h2><ol><li>评估指标是什么？</li><li>评估指标怎么算的？</li></ol><p>上下文相关性</p><blockquote><p>指的是检索到的上下文应该只包含回答问题所需的信息，这个指标旨在惩罚包含冗余信息的情况。</p></blockquote><p>评估俩方面： 上下文对不对， 上下文全部全</p><p>上下文召回率</p><blockquote><p>衡量检索到的上下文(contexts)与真实答案（ground_truths）的匹配程度。</p></blockquote><p>计算：</p><p>被推断出的句子 / 真实答案数</p><p>指标怎么算：</p><p><img src="'+n+'" alt="image-20260412213151331" loading="lazy"></p><p>忠诚度</p><p><img src="'+d+'" alt="image-20260412213728040" loading="lazy"></p><p>答案相关性</p><p>作用： 生成答案与查询直接的相关性</p><p><img src="'+c+'" alt="image-20260412214209760" loading="lazy"></p><p>3-4-5</p>',79)])])}const M=e(m,[["render",h]]);export{f as __pageData,M as default};
